def solution(start_h: int = 144) -> int:
    """
    Optimized search by generating both hexagonal and pentagonal numbers 
    and finding their intersection using a two-pointer approach.
    """
    h_idx = start_h
    p_idx = 166 # Start after P_165 = 40755

    while True:
        h_val = h_idx * (2 * h_idx - 1)
        p_val = p_idx * (3 * p_idx - 1) // 2

        if h_val == p_val:
            return h_val

        if h_val < p_val:
            h_idx += 1
        else:
            p_idx += 1


